import React, { useEffect, useState, useRef, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import { useSocket } from '../context/SocketContext';
import { requestsAPI } from '../utils/requestsAPI';
import { playNotificationSound } from './NotificationToast';

// ─── MiniChatPanel ─────────────────────────────────────────────────────────────
// Shows a list of active conversations on the dashboard.
// Clicking a conversation opens an inline chat window without navigating away.
const MiniChatPanel = ({ requests = [], onUnread }) => {
  const { user }    = useAuth();
  const { socket }  = useSocket();

  const [activeConv,   setActiveConv]   = useState(null);   // full request object
  const [messages,     setMessages]     = useState([]);
  const [msgText,      setMsgText]      = useState('');
  const [sending,      setSending]      = useState(false);
  const [loadingConv,  setLoadingConv]  = useState(false);
  const [unreadMap,    setUnreadMap]    = useState({});      // { requestId: count }
  const chatEndRef  = useRef(null);
  const inputRef    = useRef(null);

  // Requests that have a provider assigned (chatting is enabled)
  const chatableReqs = requests.filter(r =>
    r.provider && !['pending', 'cancelled'].includes(r.status)
  );

  // ── Auto-scroll chat ────────────────────────────────────────────────────────
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // ── Socket: listen for messages on ALL chatable requests ───────────────────
  useEffect(() => {
    if (!socket) return;

    // Join rooms for all chatable requests
    chatableReqs.forEach(r => socket.emit('join_request', r._id));

    const handleNewMessage = (msg) => {
      const isFromMe = msg.sender?._id?.toString() === user?._id?.toString();

      if (activeConv && msg.requestId === activeConv._id?.toString()) {
        if (isFromMe) return; // sender already added it optimistically
        // Receiver — append in real-time
        setMessages(prev => {
          const exists = prev.some(m => m._id?.toString() === msg._id?.toString());
          if (exists) return prev;
          playNotificationSound();
          return [...prev, msg];
        });
      } else if (!isFromMe) {
        // Background conversation — increment badge
        playNotificationSound();
        setUnreadMap(prev => {
          const next = { ...prev, [msg.requestId]: (prev[msg.requestId] || 0) + 1 };
          if (onUnread) onUnread(Object.values(next).reduce((a, b) => a + b, 0));
          return next;
        });
      }
    };

    socket.on('new_message', handleNewMessage);
    return () => {
      socket.off('new_message', handleNewMessage);
    };
  }, [socket, chatableReqs.length, activeConv, user?._id]);

  // Re-join on socket reconnect
  useEffect(() => {
    if (!socket) return;
    const rejoin = () => chatableReqs.forEach(r => socket.emit('join_request', r._id));
    socket.on('connect', rejoin);
    return () => socket.off('connect', rejoin);
  }, [socket, chatableReqs.length]);

  // ── Open a conversation ─────────────────────────────────────────────────────
  const openConversation = useCallback(async (req) => {
    setLoadingConv(true);
    setMessages([]);
    setMsgText('');
    try {
      const res = await requestsAPI.getById(req._id);
      const full = res.data.data;
      setActiveConv(full);
      setMessages(full.messages || []);
      // Clear unread badge for this conversation
      setUnreadMap(prev => { const n = { ...prev }; delete n[req._id]; return n; });
      setTimeout(() => inputRef.current?.focus(), 100);
    } catch {
      // ignore
    } finally {
      setLoadingConv(false);
    }
  }, []);

  const closeConversation = () => {
    setActiveConv(null);
    setMessages([]);
    setMsgText('');
  };

  // ── Send message ────────────────────────────────────────────────────────────
  const handleSend = async () => {
    if (!msgText.trim() || !activeConv || sending) return;
    const content = msgText.trim();
    setMsgText('');
    setSending(true);
    try {
      await requestsAPI.sendMessage(activeConv._id, content);
      // Socket delivers the message back to us via 'new_message'
    } catch {
      setMsgText(content);
    } finally {
      setSending(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); }
  };

  const formatTime = (d) =>
    new Date(d).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' });

  const otherPerson = (req) => {
    if (user?.role === 'provider') {
      return req.customer?.firstName ? `${req.customer.firstName} ${req.customer.lastName}` : 'Customer';
    }
    return req.provider?.firstName ? `${req.provider.firstName} ${req.provider.lastName}` : 'Provider';
  };

  const totalUnread = Object.values(unreadMap).reduce((a, b) => a + b, 0);

  return (
    <div style={{
      background: '#fff', borderRadius: '12px', border: '1px solid #e8ecf0',
      boxShadow: '0 2px 8px rgba(0,0,0,0.05)', overflow: 'hidden',
      fontFamily: "'Outfit', sans-serif",
    }}>

      {/* ── Header ──────────────────────────────────────────────────────────── */}
      <div style={{
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        padding: '14px 18px', borderBottom: '1px solid #f0f4f8',
        background: '#1a3c5e',
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
          {activeConv && (
            <button
              onClick={closeConversation}
              style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'rgba(255,255,255,0.7)', fontSize: '18px', lineHeight: 1, padding: '0 4px 0 0' }}
            >
              ←
            </button>
          )}
          <span style={{ fontSize: '14px', fontWeight: '800', color: '#fff' }}>
            {activeConv ? otherPerson(activeConv) : '💬 Messages'}
          </span>
          {!activeConv && totalUnread > 0 && (
            <span style={{ background: '#e74c3c', color: '#fff', borderRadius: '10px', padding: '1px 7px', fontSize: '11px', fontWeight: '800' }}>
              {totalUnread}
            </span>
          )}
          {activeConv && (
            <span style={{ fontSize: '11px', color: 'rgba(255,255,255,0.5)', fontStyle: 'italic' }}>
              {activeConv.title}
            </span>
          )}
        </div>
      </div>

      {/* ── Body ────────────────────────────────────────────────────────────── */}
      {!activeConv ? (

        /* Conversation list */
        <div style={{ maxHeight: '320px', overflowY: 'auto' }}>
          {chatableReqs.length === 0 ? (
            <div style={{ padding: '32px 20px', textAlign: 'center', color: '#8a9bb0', fontSize: '13px' }}>
              <div style={{ fontSize: '32px', marginBottom: '8px' }}>💬</div>
              No active conversations yet.
            </div>
          ) : (
            chatableReqs.map(req => {
              const unread = unreadMap[req._id] || 0;
              const other  = otherPerson(req);
              return (
                <button
                  key={req._id}
                  onClick={() => openConversation(req)}
                  style={{
                    width: '100%', display: 'flex', alignItems: 'center', gap: '12px',
                    padding: '12px 18px', background: unread ? '#f0f7ff' : '#fff',
                    border: 'none', borderBottom: '1px solid #f8fafc',
                    cursor: 'pointer', textAlign: 'left', fontFamily: "'Outfit', sans-serif",
                    transition: 'background 0.15s',
                  }}
                  onMouseEnter={e => e.currentTarget.style.background = '#f0f4f8'}
                  onMouseLeave={e => e.currentTarget.style.background = unread ? '#f0f7ff' : '#fff'}
                >
                  {/* Avatar */}
                  <div style={{
                    width: '38px', height: '38px', borderRadius: '50%', flexShrink: 0,
                    background: '#1a3c5e', color: '#fff',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontSize: '14px', fontWeight: '700',
                  }}>
                    {other.charAt(0).toUpperCase()}
                  </div>

                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <span style={{ fontSize: '13px', fontWeight: '700', color: '#1a2e44' }}>{other}</span>
                      {unread > 0 && (
                        <span style={{ background: '#e74c3c', color: '#fff', borderRadius: '10px', padding: '1px 7px', fontSize: '10px', fontWeight: '800', flexShrink: 0 }}>
                          {unread}
                        </span>
                      )}
                    </div>
                    <div style={{ fontSize: '11px', color: '#8a9bb0', marginTop: '2px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {req.title}
                    </div>
                  </div>
                </button>
              );
            })
          )}
        </div>

      ) : (

        /* Active chat */
        <>
          <div style={{ height: '260px', overflowY: 'auto', padding: '12px 14px', display: 'flex', flexDirection: 'column', gap: '8px', background: '#fafbfc' }}>
            {loadingConv ? (
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
                <div style={{ width: '24px', height: '24px', border: '3px solid #e8ecf0', borderTopColor: '#C17B2A', borderRadius: '50%', animation: 'spin 0.7s linear infinite' }} />
              </div>
            ) : messages.length === 0 ? (
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%', color: '#8a9bb0', fontSize: '12px', textAlign: 'center' }}>
                No messages yet — say hello!
              </div>
            ) : (
              messages.map((msg, i) => {
                const isMine = msg.sender?._id?.toString() === user?._id?.toString()
                            || msg.sender === user?._id?.toString();
                return (
                  <div key={msg._id || i} style={{ display: 'flex', flexDirection: 'column', alignItems: isMine ? 'flex-end' : 'flex-start' }}>
                    <div style={{
                      maxWidth: '80%', padding: '8px 12px',
                      borderRadius: isMine ? '12px 12px 2px 12px' : '12px 12px 12px 2px',
                      background: isMine ? '#1a3c5e' : '#fff',
                      color: isMine ? '#fff' : '#1a2e44',
                      fontSize: '12px', lineHeight: 1.5,
                      border: isMine ? 'none' : '1px solid #e8ecf0',
                      wordBreak: 'break-word',
                    }}>
                      {msg.content}
                    </div>
                    <span style={{ fontSize: '10px', color: '#aab4bf', marginTop: '2px' }}>
                      {formatTime(msg.createdAt)}
                    </span>
                  </div>
                );
              })
            )}
            <div ref={chatEndRef} />
          </div>

          {/* Input */}
          {!['completed', 'cancelled'].includes(activeConv.status) && (
            <div style={{ padding: '10px 12px', borderTop: '1px solid #f0f4f8', display: 'flex', gap: '8px', background: '#fff' }}>
              <input
                ref={inputRef}
                value={msgText}
                onChange={e => setMsgText(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Type a message…"
                style={{
                  flex: 1, padding: '8px 12px', border: '1.5px solid #dde3eb',
                  borderRadius: '8px', fontSize: '12px', fontFamily: "'Outfit', sans-serif",
                  outline: 'none', background: '#f8fafc',
                }}
              />
              <button
                onClick={handleSend}
                disabled={sending || !msgText.trim()}
                style={{
                  padding: '8px 14px', borderRadius: '8px', border: 'none',
                  background: sending || !msgText.trim() ? '#e8ecf0' : '#1a3c5e',
                  color: sending || !msgText.trim() ? '#8a9bb0' : '#fff',
                  fontSize: '12px', fontWeight: '700', cursor: sending || !msgText.trim() ? 'not-allowed' : 'pointer',
                  fontFamily: "'Outfit', sans-serif", whiteSpace: 'nowrap',
                }}
              >
                {sending ? '…' : 'Send'}
              </button>
            </div>
          )}
        </>
      )}
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
};

export default MiniChatPanel;
